const payload = $json.body ?? $json;
const headers = $json.headers ?? {};

const expectedSecret = 'REEMPLAZAR_CON_SECRETO_SIGNUP';
const receivedSecret = headers['x-lito-signup-secret'] || headers['X-Lito-Signup-Secret'] || '';

if (expectedSecret && receivedSecret !== expectedSecret) {
  throw new Error('Unauthorized webhook request');
}

const clean = (value) => (typeof value === 'string' ? value.trim() : '');
const nombre = clean(payload.nombre);
const email = clean(payload.email).toLowerCase();
const telefono = clean(payload.telefono);
const estacionServicio = clean(payload.estacionServicio);
const funcion = clean(payload.funcion);
const mensaje = clean(payload.mensaje);
const source = clean(payload.source) || 'web-sumate-modal';
const receivedAt = clean(payload.receivedAt) || new Date().toISOString();
const metadata = payload.metadata ?? {};
const userAgent = clean(metadata.userAgent) || 'n/d';
const referer = clean(metadata.referer) || 'n/d';
const forwardedFor = clean(metadata.forwardedFor) || 'n/d';

if (!nombre || !email || !telefono) {
  throw new Error('Missing required fields');
}

if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
  throw new Error('Invalid email');
}

const campaignName = 'Lista Azul y Blanca';
const campaignUrl = 'https://agj9.vercel.app';
const footerLogoUrl = `${campaignUrl}/images/logo/logo-gray.svg`;
const localReceivedAt = new Date(receivedAt).toLocaleString('es-AR', {
  timeZone: 'America/Argentina/Buenos_Aires',
  dateStyle: 'short',
  timeStyle: 'short',
});
const sheetId = 'REEMPLAZAR_CON_GOOGLE_SHEET_ID';
const sheetUrl = sheetId ? `https://docs.google.com/spreadsheets/d/${sheetId}` : '';

const subscriberSubject = `Gracias por sumarte a ${campaignName}`;
const subscriberDetails = [
  `<tr><td style='padding:0.55rem 0.75rem; border-bottom:1px solid #d8e1ef; color:#47607f; font-size:14px;'>Nombre</td><td style='padding:0.55rem 0.75rem; border-bottom:1px solid #d8e1ef; color:#172235; font-size:14px; font-weight:600;'>${nombre}</td></tr>`,
  `<tr><td style='padding:0.55rem 0.75rem; border-bottom:1px solid #d8e1ef; color:#47607f; font-size:14px;'>Email</td><td style='padding:0.55rem 0.75rem; border-bottom:1px solid #d8e1ef; color:#172235; font-size:14px; font-weight:600;'>${email}</td></tr>`,
  `<tr><td style='padding:0.55rem 0.75rem; border-bottom:1px solid #d8e1ef; color:#47607f; font-size:14px;'>Telefono</td><td style='padding:0.55rem 0.75rem; border-bottom:1px solid #d8e1ef; color:#172235; font-size:14px; font-weight:600;'>${telefono}</td></tr>`,
  `<tr><td style='padding:0.55rem 0.75rem; border-bottom:1px solid #d8e1ef; color:#47607f; font-size:14px;'>Estacion de servicio</td><td style='padding:0.55rem 0.75rem; border-bottom:1px solid #d8e1ef; color:#172235; font-size:14px; font-weight:600;'>${estacionServicio || 'No informada'}</td></tr>`,
  `<tr><td style='padding:0.55rem 0.75rem; color:#47607f; font-size:14px;'>Funcion</td><td style='padding:0.55rem 0.75rem; color:#172235; font-size:14px; font-weight:600;'>${funcion || 'No informada'}</td></tr>`,
].join('');
const subscriberMessageBlock = mensaje
  ? `<div style='margin-top:1rem; padding:1rem 1.1rem; border-radius:1rem; background:#f3f7fd; border:1px solid #d8e1ef;'><div style='margin-bottom:0.4rem; color:#0d4675; font-size:13px; font-weight:800; letter-spacing:0.04em; text-transform:uppercase;'>Tu mensaje</div><div style='color:#22324a; font-size:15px; line-height:1.6;'>${mensaje}</div></div>`
  : '';
const subscriberHtml = `
  <div style='margin:0; padding:32px 16px; background:#eef3fb; font-family:Arial, Helvetica, sans-serif; color:#172235;'>
    <table role='presentation' cellpadding='0' cellspacing='0' border='0' width='100%' style='max-width:640px; margin:0 auto; background:#ffffff; border-radius:24px; overflow:hidden; box-shadow:0 18px 48px rgba(13, 38, 66, 0.14);'>
      <tr>
        <td style='padding:40px 36px 34px; background:linear-gradient(135deg, #0d4675 0%, #2e7ed8 100%);'>
          <div style='color:rgba(255,255,255,0.78); font-size:13px; font-weight:700; letter-spacing:0.14em; text-transform:uppercase;'>Agrupacion Nueve de Julio</div>
          <div style='margin-top:10px; color:rgba(255,255,255,0.92); font-size:15px; line-height:1.35; font-weight:700; text-transform:uppercase;'>Vamos juntos por S.O.E.S.G.yP.E.</div>
          <div style='margin-top:4px; color:rgba(255,255,255,0.92); font-size:15px; line-height:1.35; font-weight:700; text-transform:uppercase;'>Cacho Garcia Conduccion</div>
          <div style='margin-top:18px; color:#ffffff; font-size:38px; line-height:1.02; font-weight:900; letter-spacing:0.03em; text-transform:uppercase;'>Gracias por sumarte</div>
          <div style='margin-top:12px; max-width:460px; color:rgba(255,255,255,0.88); font-size:16px; line-height:1.65;'>Recibimos tus datos y el equipo se va a poner en contacto con vos muy pronto.</div>
        </td>
      </tr>
      <tr>
        <td style='padding:34px 36px 18px;'>
          <div style='color:#172235; font-size:22px; line-height:1.3; font-weight:700;'>Hola ${nombre},</div>
          <div style='margin-top:12px; color:#44556f; font-size:15px; line-height:1.7;'>Te confirmamos que tu adhesión fue recibida correctamente el ${localReceivedAt}. Abajo te dejamos el resumen de los datos que nos compartiste.</div>
          <table role='presentation' cellpadding='0' cellspacing='0' border='0' width='100%' style='margin-top:22px; border:1px solid #d8e1ef; border-radius:18px; overflow:hidden; background:#ffffff;'>
            ${subscriberDetails}
          </table>
          ${subscriberMessageBlock}
          <div style='margin-top:24px; color:#44556f; font-size:15px; line-height:1.7;'>Estamos organizandonos para recuperar el gremio y cada persona que se suma hace la diferencia. Gracias por ser parte de esta construcción.</div>
          <div style='margin-top:28px;'>
            <a href='${campaignUrl}' style='display:inline-block; padding:14px 26px; border-radius:999px; background:#0d4675; color:#ffffff; text-decoration:none; font-size:15px; font-weight:700;'>Ver la campaña</a>
          </div>
        </td>
      </tr>
      <tr>
        <td style='padding:0 36px 34px;'>
          <table role='presentation' cellpadding='0' cellspacing='0' border='0' width='100%' style='margin-top:24px; padding-top:20px; border-top:1px solid #d8e1ef;'>
            <tr>
              <td style='color:#5f7089; font-size:13px; line-height:1.7; vertical-align:bottom;'>
                Lista Azul y Blanca<br />
                Agrupacion Nueve de Julio<br />
                Este correo confirma que recibimos tu suscripcion desde el formulario Sumate! iniciando asi tu proceso de adhesion.
              </td>
              <td style='width:96px; text-align:right; vertical-align:bottom;'>
                <img src='${footerLogoUrl}' alt='Logo Lista Azul y Blanca' width='76' style='display:block; margin-left:auto; width:76px; height:auto; opacity:0.68;' />
              </td>
            </tr>
          </table>
        </td>
      </tr>
    </table>
  </div>
`;

const teamSubject = `Nueva suscripcion Sumate: ${nombre}`;
const teamHtml = [
  '<p>Llego una nueva suscripcion desde el modal Sumate.</p>',
  '<ul>',
  `<li><strong>Nombre:</strong> ${nombre}</li>`,
  `<li><strong>Email:</strong> ${email}</li>`,
  `<li><strong>Telefono:</strong> ${telefono}</li>`,
  `<li><strong>Estacion de servicio:</strong> ${estacionServicio || 'No informada'}</li>`,
  `<li><strong>Funcion:</strong> ${funcion || 'No informada'}</li>`,
  `<li><strong>Origen:</strong> ${source}</li>`,
  `<li><strong>Fecha:</strong> ${localReceivedAt}</li>`,
  `<li><strong>Referer:</strong> ${referer}</li>`,
  `<li><strong>IP:</strong> ${forwardedFor}</li>`,
  '</ul>',
  mensaje ? `<p><strong>Mensaje:</strong><br>${mensaje}</p>` : '<p><strong>Mensaje:</strong> No dejo mensaje.</p>',
  sheetUrl ? `<p>Hoja: <a href="${sheetUrl}">${sheetUrl}</a></p>` : '',
].filter(Boolean).join('');

return [{
  json: {
    nombre,
    email,
    telefono,
    estacion_servicio: estacionServicio,
    funcion,
    mensaje,
    source,
    received_at: receivedAt,
    received_at_local: localReceivedAt,
    referer,
    forwarded_for: forwardedFor,
    user_agent: userAgent,
    subscriberSubject,
    subscriberHtml,
    teamSubject,
    teamHtml,
  },
}];
